package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

class CSVFormatTest {

    @Test
    void testIsEscapeCharacterSetWhenEscapeCharacterIsNull() throws Exception {
        // Create a new CSVFormat instance based on DEFAULT but with escapeCharacter null
        CSVFormat format = CSVFormat.DEFAULT.withEscape((Character) null);

        assertFalse(format.isEscapeCharacterSet(), "Escape character should not be set when null");
    }

    @Test
    void testIsEscapeCharacterSetWhenEscapeCharacterIsSet() throws Exception {
        // Create a new CSVFormat instance based on DEFAULT but with escapeCharacter set to '\\'
        CSVFormat format = CSVFormat.DEFAULT.withEscape('\\');

        assertTrue(format.isEscapeCharacterSet(), "Escape character should be set when non-null");
    }
}
